def always_spawn():
    # enforce multiprocessing start method `spawn` to prevent deadlocks in the child
    multiprocessing.set_start_method("spawn", force=True)

def suppress_slow_callbacks() -> None:
    class SuppressSlowCallbacks(logging.Filter):
        def filter(self, record: logging.LogRecord) -> bool:
            return record.msg != "Executing %s took %.3f seconds"

    # Suppress the slow callback duration warning messages interfering with log capture
    # assertions on asyncio
    logging.getLogger("asyncio").addFilter(SuppressSlowCallbacks())

def pymongo_server(request):
    mongo_uri = request.config.getoption("--mongo")
    if mongo_uri is None:
        pytest.skip(SKIP_MESSAGE_PATTERN.format(db="mongo"))
    else:
        return mongo_uri

async def pymongo_storage(pymongo_server):
    try:
        parse_mongo_url(pymongo_server)
    except InvalidURI as e:
        raise UsageError(INVALID_URI_PATTERN.format(db="mongo", uri=pymongo_server, err=e))
    storage = PyMongoStorage.from_url(
        url=pymongo_server,
        connection_kwargs={"serverSelectionTimeoutMS": 2000},
    )
    try:
        await storage._client.server_info()
    except PyMongoError as e:
        pytest.fail(str(e))
    else:
        yield storage
        await storage._client.drop_database(storage._database)
    finally:
        await storage.close()

