def input_messages() -> list[AirbyteMessage]:
    messages = []

    with Path("sample_files/messages.jsonl").open() as f:
        for line in f:
            data = json.loads(line)
            messages.append(
                AirbyteMessage(
                    type=Type.RECORD,
                    record=AirbyteRecordMessage(
                        data=data["data"],
                        emitted_at=data["emitted_at"],
                        stream=data["stream"],
                    ),
                ),
            )

    return messages

