def event_loop_policy():
    """Use SelectorEventLoop on Windows for psycopg async compatibility."""
    if sys.platform == "win32":
        return asyncio.WindowsSelectorEventLoopPolicy()
    return asyncio.DefaultEventLoopPolicy()

