def get_selenium_driver():
    from selenium import webdriver

    driver = None

    try:

        def _get_driver():
            nonlocal driver
            if driver is None:
                driver = webdriver.Chrome()
            return driver

        yield _get_driver
    finally:
        if driver:
            driver.quit()

