def parallel_machine(self):
        class TwoRegions(StateChart):
            class both(State.Parallel):
                class left(State.Compound):
                    l1 = State(initial=True)
                    l2 = State()
                    tick_l = l1.to(l2) | l2.to(l1)

                class right(State.Compound):
                    r1 = State(initial=True)
                    r2 = State()
                    tick_r = r1.to(r2) | r2.to(r1)

        return TwoRegions()

def ssh_encrypted_key(tmp_path_factory) -> dict[str, object]:
    if shutil.which("ssh-keygen") is None:
        pytest.skip("ssh-keygen not available on PATH")

    ssh_dir = tmp_path_factory.mktemp("ssh_encrypted")
    key = ssh_dir / "encrypted_ed25519"
    passphrase = "correct horse battery staple"

    subprocess.run(
        ["ssh-keygen", "-t", "ed25519", "-N", passphrase, "-f", str(key), "-C", "encrypted-test"],
        check=True,
        capture_output=True,
    )

    return {"key": key, "passphrase": passphrase}

