def systemctl_service_status():
    """ Get and pre-process systemctl output
    YIELD:  systemctl output formatted into a list of strings """

    try:
        raw_list_units = subprocess.run(['systemctl', 'list-units', '--type=service'], capture_output=True)
        svc_data = raw_list_units.stdout.decode().strip().splitlines()
        yield svc_data
    except Exception:
        pass

def smb_setup(request):
    with dataset('smb-camel', data={'share_type': 'SMB'}) as ds:
        with user({
            'username': SHAREUSER,
            'full_name': SHAREUSER,
            'group_create': True,
            'password': PASSWD
        }, get_instance=False):
            with smb_share(os.path.join('/mnt', ds), SMB_NAME) as s:
                try:
                    call('service.start', 'cifs')
                    yield {'dataset': ds, 'share': s}
                finally:
                    call('service.stop', 'cifs')

