def relay_type_defs():
    return """\
interface Node {
  bid: ID!
}

type Faction implements Node {
  bid: ID!
  name: String
  ships(first: Int!, after: ID): ShipConnection
}

type Ship implements Node {
  bid: ID!
  name: String
}

type ShipConnection {
  edges: [ShipEdge]
  pageInfo: PageInfo!
  ships: [Ship]
  totalCount: Int
}

type ShipEdge {
  cursor: String!
  node: Ship
}

type PageInfo {
  hasNextPage: Boolean!
  hasPreviousPage: Boolean!
  startCursor: String
  endCursor: String
}

type Query {
  rebels: Faction
  empire: Faction
  node(bid: ID!): Node
}
"""

