def fixture_factory(_parity_fixture_dir):
    """Return a builder that resolves a fix_id to its on-disk path.

    Files are cached across the test session: a fixture already present
    on disk is returned without rewriting.
    """
    dir_path = _parity_fixture_dir

    def _build(fix_id: str) -> Path:
        if fix_id == "vrt":
            vrt_path = dir_path / "mosaic_1813.vrt"
            if vrt_path.exists():
                return vrt_path
            return _write_vrt_mosaic(dir_path)

        safe_id = fix_id.replace("/", "-")
        path = dir_path / f"parity_{safe_id}_1813.tif"
        if path.exists():
            return path
        if fix_id.startswith("stripped/"):
            _, dtype_name, comp = fix_id.split("/")
            _write_stripped(path, np.dtype(dtype_name), comp)
        elif fix_id.startswith("tiled/"):
            _, dtype_name, comp = fix_id.split("/")
            _write_tiled(path, np.dtype(dtype_name), comp)
        elif fix_id == "cog":
            _write_cog(path)
        elif fix_id == "bigtiff":
            _write_bigtiff(path)
        elif fix_id == "miniswhite":
            _write_miniswhite(path)
        else:
            raise ValueError(f"unknown fixture id: {fix_id}")
        return path
    return _build

def lerc_writer_with_mask_1896(monkeypatch):
    """Inject a per-tile mask into the LERC writer (see #1529 / #1817).

    The xrspatial writer hard-codes ``hasMask=False`` in its
    ``lerc.encode`` call. Monkeypatch ``lerc_compress`` so the mask
    survives the encode and reappears at decode time -- the only way
    to exercise the GPU LERC mask path without an external mask-bearing
    fixture file.
    """
    holder = {"invalid": None}

    def _patched(data, width, height, samples=1,
                 dtype=np.dtype('float32'), max_z_error=0.0):
        if samples == 1:
            arr = np.frombuffer(data, dtype=dtype).reshape(height, width)
        else:
            arr = np.frombuffer(data, dtype=dtype).reshape(
                height, width, samples)
        invalid_pred = holder["invalid"]
        if invalid_pred is None:
            mask = None
            has_mask = False
        else:
            invalid = invalid_pred(arr)
            mask = np.where(invalid, np.uint8(0), np.uint8(1))
            has_mask = True
        result = lerc.encode(arr, samples, has_mask, mask, max_z_error, 1)
        if result[0] != 0:
            raise RuntimeError(
                f"LERC encode failed with error code {result[0]}")
        return bytes(result[2])

    monkeypatch.setattr(
        "xrspatial.geotiff._compression.lerc_compress", _patched,
    )
    return holder

