        super().setUp()
        self.login_as(user=self.user)
        self.authed_user = self.user

        self.start = before_now(days=1).replace(hour=10, minute=0, second=0, microsecond=0)
        self.end = self.start + timedelta(hours=2)

        self.project = self.create_project()
        self.project2 = self.create_project()
        self.user = self.create_user()
        self.user2 = self.create_user()
        transaction = load_data(
            "transaction",
            start_timestamp=self.start + timedelta(minutes=1),
            timestamp=self.start + timedelta(minutes=3),
        )
        transaction.update(
            {
                "transaction": "very bad",
                "tags": {"sentry:user": self.user.email},
            }
        )
        self.store_event(
            data=transaction,
            project_id=self.project.id,
        )
        transaction = load_data(
            "transaction",
            start_timestamp=self.start + timedelta(hours=1, minutes=1),
            timestamp=self.start + timedelta(hours=1, minutes=3),
        )
        transaction.update(
            {
                "transaction": "oh my",
                "tags": {"sentry:user": self.user2.email},
            }
        )
        self.store_event(
            data=transaction,
            project_id=self.project2.id,
        )
        transaction = load_data(
            "transaction",
            start_timestamp=self.start + timedelta(hours=1, minutes=2),
            timestamp=self.start + timedelta(hours=1, minutes=4),
        )
        transaction.update(
            {
                "transaction": "very bad",
                "tags": {"sentry:user": self.user2.email},
            }
        )
        self.store_event(
            data=transaction,
            project_id=self.project2.id,
        )
        self.url = reverse(
            "sentry-api-0-organization-events-timeseries",
            kwargs={"organization_id_or_slug": self.project.organization.slug},
        )
        self.features = {"organizations:global-views": True}

def setUp(self):
        super().setUp()
        self.login_as(user=self.user)
        self.registry = Registry[DataConditionHandler](enable_reverse_lookup=False)
        self.registry_patcher = patch(
            "sentry.workflow_engine.endpoints.organization_data_condition_index.condition_handler_registry",
            new=self.registry,
        )
        self.registry_patcher.start()

        @self.registry.register(Condition.REAPPEARED_EVENT)
        @dataclass(frozen=True)
        class TestWorkflowTrigger(DataConditionHandler):
            group = DataConditionHandler.Group.WORKFLOW_TRIGGER
            comparison_json_schema = {"type": "boolean"}

        @self.registry.register(Condition.AGE_COMPARISON)
        @dataclass(frozen=True)
        class TestActionFilter(DataConditionHandler):
            group = DataConditionHandler.Group.ACTION_FILTER
            subgroup = DataConditionHandler.Subgroup.ISSUE_ATTRIBUTES
            comparison_json_schema = {
                "type": "object",
                "properties": {
                    "value": {"type": "integer", "minimum": 0},
                },
                "required": ["value"],
                "additionalProperties": False,
            }

        @self.registry.register(Condition.ANOMALY_DETECTION)
        @dataclass(frozen=True)
        class TestDetectorTrigger(DataConditionHandler):
            group = DataConditionHandler.Group.DETECTOR_TRIGGER
            comparison_json_schema = {"type": "boolean"}

        # This legacy condition should not be included in the response
        @self.registry.register(Condition.EVERY_EVENT)
        @dataclass(frozen=True)
        class TestIgnoredCondition(DataConditionHandler):
            group = DataConditionHandler.Group.WORKFLOW_TRIGGER
            comparison_json_schema = {"type": "boolean"}

def tearDown(self) -> None:
        super().tearDown()
        self.registry_patcher.stop()

